const body = $('Node 1 — Webhook Trigger').item.json.body || {};
const desc = String(body.description || '');
const ctx = {};
const block = desc.match(/\[Audit context\]\s*([\s\S]*?)(?:\n\n\[Contract text\]|$)/);
if (block) {
  for (const line of block[1].split('\n')) {
    const m = line.match(/^([^:]+):\s*(.+)$/);
    if (m) ctx[m[1].trim().toLowerCase()] = m[2].trim();
  }
}
const contract_type = ctx['contract type'] || 'other';
const jurisdiction = ctx['jurisdiction'] || 'unknown';
const payload = {
  contract_type,
  parties: [],
  jurisdiction,
  sensitive_topics: [],
  key_concerns: [],
  routing_decision: 'reviewer_queue'
};
return [{ json: { text: JSON.stringify(payload) } }];

const item = $input.first().json;
const raw = typeof item.text === 'string' ? item.text : typeof item.output === 'string' ? item.output : '';
let stripped = String(raw).replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
let data = null;
try { data = JSON.parse(stripped); } catch (e) {
  const m = stripped.match(/\{[\s\S]*\}/);
  if (m) { try { data = JSON.parse(m[0]); } catch (e2) {} }
}
function arr(v) {
  if (Array.isArray(v)) return v.slice(0, 8).map(String);
  if (typeof v === 'string' && v.includes(',')) return v.split(',').map(s => s.trim()).filter(Boolean).slice(0, 8);
  if (v == null || v === '') return [];
  return [String(v)];
}
if (!data || typeof data !== 'object') {
  return [{ json: { output: null, extract_error: true, raw_preview: String(raw).slice(0, 500) } }];
}
const rd = ['escalation','reviewer_queue','auto_file'].includes(data.routing_decision) ? data.routing_decision : 'reviewer_queue';
return [{ json: { output: {
  contract_type: data.contract_type ?? 'other',
  parties: arr(data.parties),
  jurisdiction: data.jurisdiction ?? 'unknown',
  sensitive_topics: arr(data.sensitive_topics),
  key_concerns: arr(data.key_concerns).slice(0, 5),
  routing_decision: rd
} } }];

const agent = $('Node 5 — AI Agent').item.json || {};
const ext = ($('Node 4b — Parse extracted JSON').item.json || {}).output || {};
const raw = typeof agent.output === 'string' ? agent.output : typeof agent.text === 'string' ? agent.text : JSON.stringify(agent);
let stripped = String(raw).replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
let data = null;
try { data = JSON.parse(stripped); } catch (e) {
  const m = stripped.match(/\{[\s\S]*\}/);
  if (m) { try { data = JSON.parse(m[0]); } catch (e2) {} }
}
if (!data || typeof data !== 'object') {
  return [{ json: { text: JSON.stringify({ parse_error: true, raw_preview: String(raw).slice(0, 800), contract_type: ext.contract_type || 'other', routing_decision: 'reviewer_queue', overall_risk: 'Medium', findings: [], similar_regulations: [], rag_insight: '', confidence: 0 }) } }];
}
const findings = (data.findings || []).map(f => ({
  contract_clause_id: f.contract_clause_id || f.clause_id || 'clause_1',
  matched_regulatory_source: f.matched_regulatory_source || f.regulation_source || null,
  matched_regulatory_article: f.matched_regulatory_article || f.regulation_article || null,
  verdict: f.verdict || 'ambiguous',
  risk: f.risk || 'Medium',
  justification: String(f.justification || ''),
  confidence: Number(f.confidence || 0)
}));
const risk = data.overall_risk || 'Medium';
if (!data.routing_decision) {
  data.routing_decision = risk === 'High' ? 'escalation' : risk === 'Low' ? 'auto_file' : 'reviewer_queue';
}
const report = {
  contract_type: data.contract_type || ext.contract_type || 'other',
  routing_decision: data.routing_decision,
  jurisdiction: data.jurisdiction || ext.jurisdiction || 'unknown',
  parties: data.parties || ext.parties || [],
  overall_risk: risk,
  findings,
  similar_regulations: data.similar_regulations || [],
  rag_insight: data.rag_insight || '',
  enrichment_notes: data.enrichment_notes || 'Report from Node 5 AI Agent (rag_query + langgraph_agent tools).',
  confidence: Number(data.confidence || 0)
};
return [{ json: { text: JSON.stringify(report) } }];

const item = $input.first().json;
const raw = typeof item.text === 'string' ? item.text : typeof item.output === 'string' ? item.output : '';
let stripped = String(raw).replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
let data = null;
try { data = JSON.parse(stripped); } catch (e) {
  const m = stripped.match(/\{[\s\S]*\}/);
  if (m) { try { data = JSON.parse(m[0]); } catch (e2) {} }
}
if (data && data.report && typeof data.report === 'object') data = data.report;
const fallback = {
  contract_type: 'unknown',
  routing_decision: 'reviewer_queue',
  jurisdiction: 'unknown',
  parties: [],
  overall_risk: 'Medium',
  findings: [],
  similar_regulations: [],
  rag_insight: '',
  enrichment_notes: 'Could not parse final report JSON.',
  confidence: 0,
  parse_error: true
};
if (!data || typeof data !== 'object') {
  return [{ json: { ...fallback, raw_preview: String(raw).slice(0, 800) } }];
}
const risk = data.overall_risk || 'Medium';
if (!data.routing_decision) {
  data.routing_decision = risk === 'High' ? 'escalation' : risk === 'Low' ? 'auto_file' : 'reviewer_queue';
}
return [{ json: data }];

const webhook = $('Node 1 — Webhook Trigger').item.json.body || {};
const ext = ($('Node 4b — Parse extracted JSON').item.json.output || {});
const execId = $execution.id;
const text = String(webhook.description || '');

return [{
  json: {
    audit_id: 'aud_' + execId,
    contract_id: 'ctr_' + execId,
    clauses: [{
      id: 'clause_1',
      contract_id: 'ctr_' + execId,
      section: 'Body',
      text,
      clause_type: 'other'
    }],
    jurisdiction: String(ext.jurisdiction || 'unknown'),
    contract_type: String(ext.contract_type || 'other')
  }
}];
